package main

import (
    "fmt"
    "os"
)

// ---- defer runs after the surrounding function returns ----
func main() {
    // ---- Basic defer ----
    fmt.Println("=== Basic defer ===")
    defer fmt.Println("This runs last (3)")
    fmt.Println("This runs first (1)")
    fmt.Println("This runs second (2)")

    // ---- Multiple defers run in reverse order ----
    fmt.Println("\n=== Multiple Defers ===")
    defer fmt.Println("Defer 1 (last)")
    defer fmt.Println("Defer 2 (middle)")
    defer fmt.Println("Defer 3 (first)")

    // ---- defer with file closing ----
    fmt.Println("\n=== Defer with File ===")
    file, err := os.Create("test.txt")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer file.Close()  // File will be closed at the end

    file.WriteString("Hello, defer!")
    fmt.Println("File written")

    // ---- defer with evaluation ----
    fmt.Println("\n=== Defer Evaluation ===")
    x := 10
    defer fmt.Println("Deferred x:", x)  // Prints 10, not 20
    x = 20
    fmt.Println("After change, x:", x)

    // ---- defer with function call ----
    fmt.Println("\n=== Defer with Function ===")
    defer func() {
        fmt.Println("Deferred anonymous function")
    }()
    fmt.Println("Before deferred function")

    // ---- defer with error handling ----
    fmt.Println("\n=== Defer with Error ===")
    defer func() {
        if r := recover(); r != nil {
            fmt.Println("Recovered from:", r)
        }
    }()

    // panic("Something went wrong!")  // Uncomment to test recovery
    fmt.Println("No panic here")

    // ---- defer in a loop ----
    fmt.Println("\n=== Defer in Loop ===")
    for i := 0; i < 3; i++ {
        defer fmt.Println("Loop defer:", i)
    }
    fmt.Println("Loop complete")
}

