phase3.solution:
package main

import (
    "fmt"
    "os"
)

func main() {
    file, err := os.Create("defer_demo.txt")
    if err != nil {
        fmt.Println("Error:", err)
        return
    }
    defer file.Close()

    file.WriteString("Hello, defer!")
    fmt.Println("File written")

    defer fmt.Println("Done")

    for i := 0; i < 5; i++ {
        defer fmt.Println("Loop defer:", i)
    }

    fmt.Println("Main complete")
}
